import{_ as t,o as i,c as a,a2 as o}from"./chunks/framework.DdLJaIXX.js";const u=JSON.parse('{"title":"Compound Pilot — 4-Week Operator Playbook","description":"","frontmatter":{},"headers":[],"relativePath":"pilot/README.md","filePath":"pilot/README.md"}'),r={name:"pilot/README.md"};function s(l,e,n,d,h,c){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="compound-pilot-—-4-week-operator-playbook" tabindex="-1">Compound Pilot — 4-Week Operator Playbook <a class="header-anchor" href="#compound-pilot-—-4-week-operator-playbook" aria-label="Permalink to &quot;Compound Pilot — 4-Week Operator Playbook&quot;">​</a></h1><blockquote><p><strong>Purpose</strong>: Validate that the CQ Compound loop triggers naturally in the wild. Pass threshold γ: at least one pilot user declares a derives_from chain ≥ 3 deep within the 4-week window — without any nudges or artificial prompts.</p></blockquote><hr><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The 4-week pilot measures whether BYO-GPU researchers, left to work naturally with CQ, spontaneously build experiment chains that form a Compound loop. This is the critical early-market signal before broader rollout (Stage 4/5).</p><p>The single hypothesis: <strong>Compound loop will emerge without encouragement.</strong></p><p>γ threshold: at least 1 pilot user with <code>derives_from</code> chain depth ≥ 3.</p><p>All measurement is passive. No nudges, no &quot;try this next&quot; suggestions, no proactive outreach during the pilot window.</p><hr><h2 id="pre-flight-checklist" tabindex="-1">Pre-Flight Checklist <a class="header-anchor" href="#pre-flight-checklist" aria-label="Permalink to &quot;Pre-Flight Checklist&quot;">​</a></h2><p>Before inviting the first participant, confirm <strong>all</strong> of the following:</p><ul><li>[ ] <strong>T-SLO-3 merged</strong> — <code>/me/compound</code> personal dashboard live (R11)</li><li>[ ] <strong>T-OBD-1 – T-OBD-8 merged</strong> — invite code + worker register flow live (R2, R4, R5)</li><li>[ ] <strong>T-CP-1 merged</strong> — <code>pilot_cohort_metrics</code>, <code>pilot_chain_depth</code>, <code>pilot_verdict</code> in production</li><li>[ ] <strong>T-CP-2 merged</strong> — <code>cq pilot report</code> CLI available in release binary</li><li>[ ] <strong>RLS verified</strong> — each pilot user&#39;s data is isolated (no cross-user leakage)</li><li>[ ] <strong>Feature freeze active</strong> — nudge / recommend_next / proactive_suggest code paths disabled</li><li>[ ] <strong>Invite codes generated</strong> — 5 codes, one per participant</li><li>[ ] <strong>Pilot start date recorded</strong> — used as <code>--since</code> in <code>cq pilot report</code></li><li>[ ] <strong>Operator contact established</strong> — Telegram handle or form URL confirmed with each participant</li></ul><hr><h2 id="week-0-participant-selection-invite-code-issuance" tabindex="-1">Week 0: Participant Selection + Invite Code Issuance <a class="header-anchor" href="#week-0-participant-selection-invite-code-issuance" aria-label="Permalink to &quot;Week 0: Participant Selection + Invite Code Issuance&quot;">​</a></h2><h3 id="selection-criteria" tabindex="-1">Selection criteria <a class="header-anchor" href="#selection-criteria" aria-label="Permalink to &quot;Selection criteria&quot;">​</a></h3><ul><li>BYO-GPU researcher (has their own GPU hardware or cloud GPU access)</li><li>Already runs iterative ML/DL experiments (at least 2 per week historically)</li><li>Willing to install CQ and use it as primary session tool for 4 weeks</li><li>No prior CQ usage (to avoid training effect)</li></ul><h3 id="invite-code-issuance" tabindex="-1">Invite code issuance <a class="header-anchor" href="#invite-code-issuance" aria-label="Permalink to &quot;Invite code issuance&quot;">​</a></h3><ol><li>Generate 5 invite codes via the invite code admin interface.</li><li>Send each participant the invite message from <code>invite-template.md</code>.</li><li>Log the mapping: <code>invite_code → participant_handle</code> in a private document.</li><li>Record the pilot start date (<code>PILOT_START=YYYY-MM-DD</code>).</li></ol><p>Do <strong>not</strong> share invite codes publicly. Each code is single-use and ties the participant to their own isolated team.</p><hr><h2 id="week-1–4-no-touch-period" tabindex="-1">Week 1–4: No-Touch Period <a class="header-anchor" href="#week-1–4-no-touch-period" aria-label="Permalink to &quot;Week 1–4: No-Touch Period&quot;">​</a></h2><p>The no-touch principle is the single most important rule of the pilot.</p><h3 id="what-operators-must-not-do" tabindex="-1">What operators MUST NOT do <a class="header-anchor" href="#what-operators-must-not-do" aria-label="Permalink to &quot;What operators MUST NOT do&quot;">​</a></h3><ul><li>Do not send &quot;how is it going?&quot; messages.</li><li>Do not suggest experiments to run.</li><li>Do not share other participants&#39; results.</li><li>Do not deploy any new features that add nudges or suggestions.</li><li>Do not change onboarding copy or email broadcasts to pilot users.</li><li>Do not announce pilot results publicly until Week 4 closes.</li></ul><h3 id="what-operators-may-do" tabindex="-1">What operators MAY do <a class="header-anchor" href="#what-operators-may-do" aria-label="Permalink to &quot;What operators MAY do&quot;">​</a></h3><ul><li>Answer direct support questions (installation failures, auth issues).</li><li>Fix critical bugs unrelated to the Compound loop (P0/P1 only — see feature-freeze-checklist.md).</li><li>Monitor error logs passively.</li></ul><h3 id="weekly-operator-check-5-minutes-optional" tabindex="-1">Weekly operator check (5 minutes, optional) <a class="header-anchor" href="#weekly-operator-check-5-minutes-optional" aria-label="Permalink to &quot;Weekly operator check (5 minutes, optional)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Confirm pilot users are authenticated and active (no diagnostic data leaked).</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pilot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> report</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --since</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PILOT_START</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/pilot-draft.md</span></span></code></pre></div><p>Do not share this draft with participants.</p><hr><h2 id="week-4-end-cq-pilot-report-interpretation" tabindex="-1">Week 4 End: <code>cq pilot report</code> + Interpretation <a class="header-anchor" href="#week-4-end-cq-pilot-report-interpretation" aria-label="Permalink to &quot;Week 4 End: `cq pilot report` + Interpretation&quot;">​</a></h2><h3 id="generate-the-final-report" tabindex="-1">Generate the final report <a class="header-anchor" href="#generate-the-final-report" aria-label="Permalink to &quot;Generate the final report&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pilot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> report</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --since</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YYYY-MM-DD</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --until</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YYYY-MM-DD</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pilot-final.md</span></span></code></pre></div><p>Replace <code>YYYY-MM-DD</code> with the actual pilot start and end dates.</p><h3 id="interpret-the-verdict" tabindex="-1">Interpret the verdict <a class="header-anchor" href="#interpret-the-verdict" aria-label="Permalink to &quot;Interpret the verdict&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Verdict</th><th>Meaning</th><th>Next Step</th></tr></thead><tbody><tr><td><strong>pass</strong></td><td>≥ 1 user reached chain depth ≥ 3 (γ met)</td><td>Proceed to Stage 4/5 (broader rollout)</td></tr><tr><td><strong>inconclusive</strong></td><td>No user submitted a 2nd experiment</td><td>Re-examine Compound hypothesis; consider Stage 1 (entry) rework</td></tr><tr><td><strong>fail</strong></td><td>Activity recorded but γ not met</td><td>Stage 1 rework is a required prerequisite before re-running</td></tr></tbody></table><h3 id="verdict-actions" tabindex="-1">Verdict actions <a class="header-anchor" href="#verdict-actions" aria-label="Permalink to &quot;Verdict actions&quot;">​</a></h3><h4 id="pass" tabindex="-1">pass <a class="header-anchor" href="#pass" aria-label="Permalink to &quot;pass&quot;">​</a></h4><ul><li>Archive <code>pilot-final.md</code> in the project knowledge base.</li><li>Tag the pilot cohort for Stage 4/5 early access.</li><li>Remove the feature freeze.</li><li>Announce internally.</li></ul><h4 id="inconclusive" tabindex="-1">inconclusive <a class="header-anchor" href="#inconclusive" aria-label="Permalink to &quot;inconclusive&quot;">​</a></h4><ul><li>Do not proceed to Stage 4/5.</li><li>Run a structured retrospective: why did users not run a 2nd experiment? <ul><li>Was the entry experience (T-OBD-1~8) confusing?</li><li>Was the GPU setup too high-friction?</li><li>Was the value proposition unclear?</li></ul></li><li>Document findings and feed back into the Compound hypothesis.</li><li>Re-run the pilot only after Stage 1 changes are validated.</li></ul><h4 id="fail" tabindex="-1">fail <a class="header-anchor" href="#fail" aria-label="Permalink to &quot;fail&quot;">​</a></h4><ul><li>Stage 1 rework is a <strong>mandatory prerequisite</strong> (R9).</li><li>Do not attempt partial rollout.</li><li>Document the specific failure pattern (which chain depths were reached, by how many users).</li><li>This data is the primary input for Stage 1 redesign.</li></ul><hr><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ul><li>Spec: <code>docs/specs/compound-pilot-4week.md</code></li><li>Design decisions: <code>.c4/designs/compound-pilot-4week.md</code> (DEC-001 – DEC-005)</li><li>Feature freeze rules: <code>docs/pilot/feature-freeze-checklist.md</code></li><li>Invite template: <code>docs/pilot/invite-template.md</code></li><li>CLI: <code>cq pilot report --help</code></li></ul>',46)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
